func (fx *MetadataServiceExecutionTestSuiteConfig) testCreate(t *testing.T) {
	fx.maybeSkip(t)
	// Method should fail with InvalidArgument if no parent is provided.
	t.Run("missing parent", func(t *testing.T) {
		fx.maybeSkip(t)
		req := &CreateExecutionRequest{}
		req.SetParent("")
		req.SetExecution(fx.Create(fx.nextParent(t, false)))
		_, err := fx.Service().CreateExecution(fx.Context(), req)
		assert.Equal(t, codes.InvalidArgument, status.Code(err), err)
	})

	// Method should fail with InvalidArgument if provided parent is invalid.
	t.Run("invalid parent", func(t *testing.T) {
		fx.maybeSkip(t)
		req := &CreateExecutionRequest{}
		req.SetParent("invalid resource name")
		req.SetExecution(fx.Create(fx.nextParent(t, false)))
		_, err := fx.Service().CreateExecution(fx.Context(), req)
		assert.Equal(t, codes.InvalidArgument, status.Code(err), err)
	})

	// Field create_time should be populated when the resource is created.
	t.Run("create time", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		beforeCreate := time.Now()
		req := &CreateExecutionRequest{}
		req.SetParent(parent)
		req.SetExecution(fx.Create(parent))
		msg, err := fx.Service().CreateExecution(fx.Context(), req)
		assert.NilError(t, err)
		assert.Check(t, msg.GetCreateTime() != nil)
		assert.Check(t, !msg.GetCreateTime().AsTime().IsZero())
		assert.Check(t, msg.GetCreateTime().AsTime().After(beforeCreate), "msg.GetCreateTime() (%v) is not after beforeCreate (%v)", msg.GetCreateTime().AsTime(), beforeCreate)
	})

	// The created resource should be persisted and reachable with Get.
	t.Run("persisted", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		getReq := &CreateExecutionRequest{}
		getReq.SetParent(parent)
		getReq.SetExecution(fx.Create(parent))
		msg, err := fx.Service().CreateExecution(fx.Context(), getReq)
		assert.NilError(t, err)
		createReq := &GetExecutionRequest{}
		createReq.SetName(msg.GetName())
		persisted, err := fx.Service().GetExecution(fx.Context(), createReq)
		assert.NilError(t, err)
		assert.DeepEqual(t, msg, persisted, protocmp.Transform())
	})

	// Field etag should be populated when the resource is created.
	t.Run("etag populated", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		req := &CreateExecutionRequest{}
		req.SetParent(parent)
		req.SetExecution(fx.Create(parent))
		created, err := fx.Service().CreateExecution(fx.Context(), req)
		assert.NilError(t, err)
		assert.Check(t, created.GetEtag() != "")
	})

}

