func (fx *MetadataServiceMetadataSchemaTestSuiteConfig) testList(t *testing.T) {
	fx.maybeSkip(t)
	// Method should fail with InvalidArgument if provided parent is invalid.
	t.Run("invalid parent", func(t *testing.T) {
		fx.maybeSkip(t)
		req := &ListMetadataSchemasRequest{}
		req.SetParent("invalid resource name")
		_, err := fx.Service().ListMetadataSchemas(fx.Context(), req)
		assert.Equal(t, codes.InvalidArgument, status.Code(err), err)
	})

	// Method should fail with InvalidArgument is provided page token is not valid.
	t.Run("invalid page token", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		req := &ListMetadataSchemasRequest{}
		req.SetParent(parent)
		req.SetPageToken("invalid page token")
		_, err := fx.Service().ListMetadataSchemas(fx.Context(), req)
		assert.Equal(t, codes.InvalidArgument, status.Code(err), err)
	})

	// Method should fail with InvalidArgument is provided page size is negative.
	t.Run("negative page size", func(t *testing.T) {
		fx.maybeSkip(t)
		parent := fx.nextParent(t, false)
		req := &ListMetadataSchemasRequest{}
		req.SetParent(parent)
		req.SetPageSize(-10)
		_, err := fx.Service().ListMetadataSchemas(fx.Context(), req)
		assert.Equal(t, codes.InvalidArgument, status.Code(err), err)
	})

	{
		const resourcesCount = 5
		parent := fx.nextParent(t, true)
		parentMsgs := make([]*MetadataSchema, resourcesCount)
		for i := 0; i < resourcesCount; i++ {
			parentMsgs[i] = fx.create(t, parent)
		}

		// If parent is provided the method must only return resources
		// under that parent.
		t.Run("isolation", func(t *testing.T) {
			fx.maybeSkip(t)
			req := &ListMetadataSchemasRequest{}
			req.SetParent(parent)
			req.SetPageSize(999)
			response, err := fx.Service().ListMetadataSchemas(fx.Context(), req)
			assert.NilError(t, err)
			assert.DeepEqual(
				t,
				parentMsgs,
				response.GetMetadataSchemas(),
				cmpopts.SortSlices(func(a, b *MetadataSchema) bool {
					return a.GetName() < b.GetName()
				}),
				protocmp.Transform(),
			)
		})

		// If there are no more resources, next_page_token should not be set.
		t.Run("last page", func(t *testing.T) {
			fx.maybeSkip(t)
			req := &ListMetadataSchemasRequest{}
			req.SetParent(parent)
			req.SetPageSize(resourcesCount)
			response, err := fx.Service().ListMetadataSchemas(fx.Context(), req)
			assert.NilError(t, err)
			assert.Equal(t, "", response.GetNextPageToken())
		})

		// If there are more resources, next_page_token should be set.
		t.Run("more pages", func(t *testing.T) {
			fx.maybeSkip(t)
			req := &ListMetadataSchemasRequest{}
			req.SetParent(parent)
			req.SetPageSize(resourcesCount - 1)
			response, err := fx.Service().ListMetadataSchemas(fx.Context(), req)
			assert.NilError(t, err)
			assert.Check(t, response.GetNextPageToken() != "")
		})

		// Listing resource one by one should eventually return all resources.
		t.Run("one by one", func(t *testing.T) {
			fx.maybeSkip(t)
			msgs := make([]*MetadataSchema, 0, resourcesCount)
			var nextPageToken string
			for {
				req := &ListMetadataSchemasRequest{}
				req.SetParent(parent)
				req.SetPageSize(1)
				req.SetPageToken(nextPageToken)
				response, err := fx.Service().ListMetadataSchemas(fx.Context(), req)
				assert.NilError(t, err)
				assert.Equal(t, 1, len(response.GetMetadataSchemas()))
				msgs = append(msgs, response.GetMetadataSchemas()...)
				nextPageToken = response.GetNextPageToken()
				if nextPageToken == "" {
					break
				}
			}
			assert.DeepEqual(
				t,
				parentMsgs,
				msgs,
				cmpopts.SortSlices(func(a, b *MetadataSchema) bool {
					return a.GetName() < b.GetName()
				}),
				protocmp.Transform(),
			)
		})

		// When listing resource with page size zero the service should use a default value.
		t.Run("page size zero", func(t *testing.T) {
			fx.maybeSkip(t)
			req := &ListMetadataSchemasRequest{}
			req.SetParent(parent)
			req.SetPageSize(0)
			response, err := fx.Service().ListMetadataSchemas(fx.Context(), req)
			assert.NilError(t, err)
			// Server should use a default page size and return at least some results
			assert.Check(t, len(response.GetMetadataSchemas()) > 0, "expected server to return at least 1 resource with page_size=0")
		})

	}
}

func (fx *MetadataServiceMetadataSchemaTestSuiteConfig) nextParent(t *testing.T, pristine bool) string {
	if pristine {
		fx.currParent++
	}
	if fx.currParent >= len(fx.Parents) {
		t.Fatal("need at least", fx.currParent+1, "parents")
	}
	return fx.Parents[fx.currParent]
}

func (fx *MetadataServiceMetadataSchemaTestSuiteConfig) peekNextParent(t *testing.T) string {
	next := fx.currParent + 1
	if next >= len(fx.Parents) {
		t.Fatal("need at least", next+1, "parents")
	}
	return fx.Parents[next]
}

func (fx *MetadataServiceMetadataSchemaTestSuiteConfig) maybeSkip(t *testing.T) {
	for _, skip := range fx.Skip {
		if strings.Contains(t.Name(), skip) {
			t.Skip("skipped because of .Skip")
		}
	}
}

func (fx *MetadataServiceMetadataSchemaTestSuiteConfig) create(t *testing.T, parent string) *MetadataSchema {
	t.Helper()
	req := &CreateMetadataSchemaRequest{}
	req.SetParent(parent)
	req.SetMetadataSchema(fx.Create(parent))
	created, err := fx.Service().CreateMetadataSchema(fx.Context(), req)
	assert.NilError(t, err)
	return created
}

type MetadataServiceMetadataStoreTestSuiteConfig struct {
	currParent int

	// Service should return the service that should be tested.
	// The service will be used for several tests.
	Service func() MetadataServiceServer
	// Context should return a new context.
	// The context will be used for several tests.
	Context func() context.Context
	// The parents to use when creating resources.
	// At least one parent needs to be set. Depending on methods available on the resource,
	// more may be required. If insufficient number of parents are
	// provided the test will fail.
	Parents []string
	// Create should return a resource which is valid to create, i.e.
	// all required fields set.
	Create func(parent string) *MetadataStore
	// Patterns of tests to skip.
	// For example if a service has a Get method:
	// Skip: ["Get"] will skip all tests for Get.
	// Skip: ["Get/persisted"] will only skip the subtest called "persisted" of Get.
	Skip []string
}

